final:
module RefModule(
    input clk,
    input async_in,
    input reset,
    output reg sync_out
    );reg obf_meta;

always @(posedge clk) 
    if (reset)
       begin
        obf_meta <= 1'b0;
        sync_out <= 1'b0;
       end
    else
       begin
        obf_meta <= async_in;
        sync_out <= obf_meta;
       end


endmodule
